import{_ as t,V as e,W as d,a1 as s}from"./framework.46148295.js";const r={},E=s(`<h1 id="mysql-创建用户及授权" tabindex="-1"><a class="header-anchor" href="#mysql-创建用户及授权" aria-hidden="true">#</a> MySQL 创建用户及授权</h1><h2 id="mysql-创建用户及授权-1" tabindex="-1"><a class="header-anchor" href="#mysql-创建用户及授权-1" aria-hidden="true">#</a> MySql 创建用户及授权</h2><p>查看MySql数据库所有用户<br><code>mysql&gt; SELECT DISTINCT CONCAT(&#39;User: &#39;&#39;&#39;,user,&#39;&#39;&#39;@&#39;&#39;&#39;,host,&#39;&#39;&#39;;&#39;) AS query FROM mysql.user;</code></p><p>查看数据库中具体某个用户的权限<br><code>mysql&gt; show grants for &#39;cactiuser&#39;@&#39;%&#39;; </code></p><p>一、创建用户：<br><code>mysql&gt; CREATE USER &#39;username&#39;@&#39;host&#39; IDENTIFIED BY &#39;password&#39;; </code></p><p>说明:<br> username - 你将创建的用户名,<br> host - 指定该用户在哪个主机上可以登陆,如果是本地用户可用localhost,如果想让该用户可以从任意远程主机登陆,可以使用通配符%.<br> password - 该用户的登陆密码,密码可以为空,如果为空则该用户可以不需要密码登陆服务器.</p><p>例子:</p><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>CREATE USER &#39;dog&#39;@&#39;localhost&#39; IDENTIFIED BY &#39;123456&#39;; 
CREATE USER &#39;pig&#39;@&#39;192.168.1.101_&#39; IDENDIFIED BY &#39;123456&#39;; 
CREATE USER &#39;pig&#39;@&#39;%&#39; IDENTIFIED BY &#39;123456&#39;; 
CREATE USER &#39;pig&#39;@&#39;%&#39; IDENTIFIED BY &#39;&#39;; 
CREATE USER &#39;pig&#39;@&#39;%&#39;;
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>二、授权：</p><p><code>mysql&gt; GRANT privileges ON databasename.tablename TO &#39;username&#39;@&#39;host&#39;</code></p><p>说明:<br> privileges : 用户的操作权限,如SELECT , INSERT , UPDATE 等(详细列表见该文最后面).如果要授予所的权限则使用ALL.;<br> databasename : 数据库名,<br> tablename : 表名,如果要授予该用户对所有数据库和表的相应操作权限则可用 * 表示, 如<code>*.*</code></p><p>例子:<br><code>GRANT SELECT, INSERT ON test.user TO &#39;pig&#39;@&#39;%&#39;; </code><br><code>GRANT ALL ON *.* TO &#39;pig&#39;@&#39;%&#39;; </code></p><p><strong>注意:用以上命令授权的用户不能给其它用户授权,如果想让该用户可以授权,用以下</strong><br><code>mysql&gt; GRANT privileges ON databasename.tablename TO &#39;username&#39;@&#39;host&#39; WITH GRANT OPTION; </code></p><p>三.设置与更改用户密码</p><p><code>mysql&gt; SET PASSWORD FOR &#39;username&#39;@&#39;host&#39; = PASSWORD(&#39;newpassword&#39;);</code><br> 如果是当前登陆用户用SET PASSWORD = PASSWORD(&quot;newpassword&quot;);</p><p>四.撤销用户权限</p><p><code>mysql&gt; REVOKE privilege ON databasename.tablename FROM &#39;username&#39;@&#39;host&#39;; </code></p><p>说明：privilege, databasename, tablename - 同授权部分。</p><p>例子：<code>REVOKE SELECT ON *.* FROM &#39;pig&#39;@&#39;%&#39;; </code></p><blockquote><p>注意: 假如你在给用户&#39;pig&#39;@&#39;%&#39;授权的时候是这样的(或类似的):<code>GRANT SELECT ON test.user TO &#39;pig&#39;@&#39;%&#39;,</code> 则在使用<code>REVOKE SELECT ON *.* FROM &#39;pig&#39;@&#39;%&#39;;</code>命令并不能撤销该用户对test数据库中user表的SELECT 操作。相反,如果授权使用的是<code>GRANT SELECT ON *.* TO &#39;pig&#39;@&#39;%&#39;;</code>则<code>REVOKE SELECT ON test.user FROM &#39;pig&#39;@&#39;%&#39;;</code>命令也不能撤销该用户对test数据库中user表的Select 权限.</p></blockquote><p>具体信息可以用命令SHOW GRANTS FOR &#39;pig&#39;@&#39;%&#39;; 查看.</p><p>五.删除用户</p><p><code>mysql&gt; DROP USER &#39;username&#39;@&#39;host&#39;; </code></p><p>附表:在MySQL中的操作权限</p><table><thead><tr><th>Privilege</th><th>Description</th></tr></thead><tbody><tr><td>ALTER</td><td>Allows use of ALTER TABLE.</td></tr><tr><td>ALTER ROUTINE</td><td>Alters or drops stored routines.</td></tr><tr><td>CREATE</td><td>Allows use of CREATE TABLE.</td></tr><tr><td>CREATE ROUTINE</td><td>Creates stored routines.</td></tr><tr><td>CREATE TEMPORARY TABLE</td><td>Allows use of CREATE TEMPORARY TABLE.</td></tr><tr><td>CREATE USER</td><td>Allows use of CREATE USER, DROP USER, RENAME USER, and REVOKE ALL PRIVILEGES.</td></tr><tr><td>CREATE VIEW</td><td>Allows use of CREATE VIEW.</td></tr><tr><td>DELETE</td><td>Allows use of DELETE.</td></tr><tr><td>DROP</td><td>Allows use of DROP TABLE.</td></tr><tr><td>EXECUTE</td><td>Allows the user to run stored routines.</td></tr><tr><td>FILE</td><td>Allows use of SELECT... INTO OUTFILE and LOAD DATA INFILE.</td></tr><tr><td>INDEX</td><td>Allows use of CREATE INDEX and DROP INDEX.</td></tr><tr><td>INSERT</td><td>Allows use of INSERT.</td></tr><tr><td>LOCK TABLES</td><td>Allows use of LOCK TABLES on tables for which the user also has SELECT privileges.</td></tr><tr><td>PROCESS</td><td>Allows use of SHOW FULL PROCESSLIST.</td></tr><tr><td>RELOAD</td><td>Allows use of FLUSH.</td></tr><tr><td>REPLICATION</td><td>Allows the user to ask where slave or master</td></tr><tr><td>CLIENT</td><td>servers are.</td></tr><tr><td>REPLICATION SLAVE</td><td>Needed for replication slaves.</td></tr><tr><td>SELECT</td><td>Allows use of SELECT.</td></tr><tr><td>SHOW DATABASES</td><td>Allows use of SHOW DATABASES.</td></tr><tr><td>SHOW VIEW</td><td>Allows use of SHOW CREATE VIEW.</td></tr><tr><td>SHUTDOWN</td><td>Allows use of mysqladmin shutdown.</td></tr><tr><td>SUPER</td><td>Allows use of CHANGE MASTER, KILL, PURGE MASTER LOGS, and SET GLOBAL SQL statements. Allows mysqladmin debug command. Allows one extra connection to be made if maximum connections are reached.</td></tr><tr><td>UPDATE</td><td>Allows use of UPDATE.</td></tr><tr><td>USAGE</td><td>Allows connection without any specific privileges.</td></tr></tbody></table>`,25),o=[E];function l(a,A){return e(),d("div",null,o)}const n=t(r,[["render",l],["__file","auth.html.vue"]]);export{n as default};
